        if lower.contains("unproductive") {
            m.unproductive_secs += r.duration_seconds;
        } else if lower.contains("productive") {
            m.productive_secs += r.duration_seconds;
        } else if lower.contains("passive") {
            m.passive_secs += r.duration_seconds;
        } else {
            m.uncategorized_secs += r.duration_seconds;
        }
        m.total_secs += r.duration_seconds;
    }

    Ok(m)
}

