/// Return today's total context switches and elapsed seconds (max - min timestamp) for rate calculation.
/// Returns `None` when there are no activity records today.
///
/// # Errors
///
/// Returns `TrackerError::Database` if the query fails.
pub fn get_today_activity_span_and_switches(
    conn: &Connection,
) -> Result<Option<(i64, i64)>, TrackerError> {
    let mut stmt = conn.prepare(
        "SELECT SUM(is_context_switch), (strftime('%s', MAX(timestamp)) - strftime('%s', MIN(timestamp)))
         FROM activity_log WHERE date(timestamp) = date('now')",
    )?;
    let mut rows = stmt.query([])?;
    let row = rows.next()?.ok_or(TrackerError::Database(
        rusqlite::Error::QueryReturnedNoRows,
    ))?;
    let switches: Option<i64> = row.get(0)?;
    let span: Option<i64> = row.get(1)?;
    Ok(match (switches, span) {
        (Some(s), Some(p)) if p >= 0 => Some((s, p)),
        _ => None,
    })
}

