/// Recompute today's focus score, deep work minutes, and context switches from raw activity.
///
/// # Errors
///
/// Returns a database error if queries fail.
pub fn recompute_today_metrics(
    conn: &Connection,
    config: &TrackerConfig,
) -> anyhow::Result<TodayRecomputed> {
    let records = db::get_raw_activity_today(conn)?;
    let rule_set = RuleSet::load(config.productivity.rules_file.as_deref());
    let away = &config.tracker.away_executables;

    if records.is_empty() {
        return Ok(TodayRecomputed {
            focus_score: 0,
            deep_work_minutes: 0.0,
            context_switches: 0,
        });
    }

    // Build deep-work sessions (exclude away).
    let sessions: Vec<DeepWorkSession> = records
        .iter()
        .filter(|r| !away.iter().any(|a| a.eq_ignore_ascii_case(&r.executable_name)))
        .map(|r| {
            let url = if r.url.is_empty() {
                None
