            let lower = status.to_lowercase();
            let is_productive =
                lower.contains("productive") && !lower.contains("unproductive");
            #[allow(clippy::cast_precision_loss)]
            let duration_minutes = r.duration_seconds as f64 / 60.0;
            DeepWorkSession {
                app_name: r.executable_name.clone(),
                is_productive,
                duration_minutes,
            }
        })
        .collect();

    let detector = DeepWorkDetector::new(DeepWorkConfig {
        min_streak_minutes: config.deep_work.min_streak_minutes,
        grace_period_secs: config.deep_work.grace_period_secs,
    });
