    let total_tracked_minutes = total_secs as f64 / 60.0;
    #[allow(clippy::cast_precision_loss)]
    let productive_minutes = m.productive_secs as f64 / 60.0;

    let span_and_switches = db::get_today_activity_span_and_switches(conn)?;
    #[allow(clippy::cast_precision_loss)]
    let switches_per_hour = match span_and_switches {
        Some((_, span_secs)) if span_secs > 0 => {
            (context_switches as f64) / (span_secs as f64 / 3_600.0)
        }
        _ => 0.0,
    };

    let weights = FocusScoreWeights {
        deep_work: config.focus_score.weight_deep_work,
        switch_rate: config.focus_score.weight_switch_rate,
        productive: config.focus_score.weight_productive,
    };
    let calc = FocusScoreCalculator::new(weights);
    let input = FocusScoreInput {
        deep_work_minutes,
        total_tracked_minutes,
        switches_per_hour,
        max_switches_per_hour: config.focus_score.max_switches_per_hour as f64,
        productive_minutes,
    };
    let focus_score = calc.compute(&input);

    Ok(TodayRecomputed {
        focus_score,
        deep_work_minutes,
        context_switches,
    })
